import{_ as e,o as n,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Funnel (New)","description":"","frontmatter":{"title":"Funnel (New)","slug":"funnel-new"},"headers":[],"relativePath":"marketer-hub/funnel-new.md","filePath":"marketer-hub/funnel-new.md"}'),r={name:"marketer-hub/funnel-new.md"};function i(s,t,l,d,h,u){return n(),a("div",null,[...t[0]||(t[0]=[o('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p><a href="https://branchdocs.app.link/funnel-new" target="_blank" rel="noreferrer">Funnel Analysis</a> simplifies multi-touch attribution reporting by visualizing the journey users take across your campaigns before converting. Instead of viewing only the last touchpoint before a conversion event, you can see the sequence of up to three interactions that led to each conversion.</p><p>Traditional last-touch attribution assigns full credit to the final touchpoint a user interacted with before converting. This model can potentially undervalue assisted touchpoints, which are touchpoints that play important roles earlier in the user journey but don&#39;t receive last-click credit.</p><p>Funnel addresses the limitations of last-touch attribution by tracking and displaying the full path users take, enabling you to understand how different interactions work together to drive conversions.</p><p>With Funnel, you can:</p><ul><li>View aggregated paths showing how users moved between touchpoints before converting.</li><li>Compare conversion paths across different dimensions such as campaigns, ad partners, and other attributes.</li><li>Analyze user journeys leading to any type of conversion event including installs, <a href="https://help.branch.io/developers-hub/docs/track-branch-events#:~:text=and%20Custom.-,Standard%20Events,-Standard%20Events%20have" target="_blank" rel="noreferrer">Branch Standard Events</a> like “Add to Cart”, or other <a href="https://help.branch.io/developers-hub/docs/track-branch-events#:~:text=COPY-,Custom%20Events,-Custom%20Events%20are" target="_blank" rel="noreferrer">Branch Custom Events</a> that you’ve defined.</li><li>Identify touchpoints that serve as effective entry points versus those that drive final conversions.</li><li>Understand the role of assisted touches, where channels may receive little last-touch credit but significantly influence user behavior.</li></ul><p>This path-level insight allows you to make more informed budget allocation decisions by accounting for the contribution of more touchpoints in the conversion journey, not just the final interaction.</p><h4 id="overlapping-lookback-windows" tabindex="-1">Overlapping lookback windows <a class="header-anchor" href="#overlapping-lookback-windows" aria-label="Permalink to &quot;Overlapping lookback windows&quot;">​</a></h4><p>Funnel supports overlapping lookback windows, allowing each partner to maintain its own attribution window length simultaneously.</p><p>In traditional attribution, when a user converts, the most recent touchpoint within an active window receives credit, effectively cutting off earlier partners from their full lookback periods.</p><p>With Funnel, each partner’s attribution window runs independently. If a user interacts with multiple ad partners and then converts after some partners’ windows have expired, the conversion is still attributed to the last partner whose window is still active. This is true even if that partner wasn’t the most recent touchpoint.</p><p>This approach ensures that partners with longer attribution windows can receive credit for conversions that occur throughout their full window period, providing a more accurate view of each partner’s contribution to user behavior over time.</p><p><strong>Set attribution windows</strong></p><p>To set your global attribution windows at the app level:</p><ol><li>In Branch, go to <strong>Configuration &gt;</strong> <a href="https://branchdocs.app.link/funnel-to-attribution" target="_blank" rel="noreferrer"><strong>Attribution</strong></a>.</li><li><a href="./attribution-page-new.html#attribution-windows">Set your values</a> for the various attribution types.</li></ol><p>To set custom attribution windows at the ad partner level:</p><ol><li>In Branch, go to <strong>Configuration &gt;</strong> <strong>Ad Partners</strong>.</li><li>Find the ad partner you want to update in the list of ad partners.</li><li>Select the <strong>Attribution Windows</strong> tab.</li><li>Turn off the “<strong>Use ad partner attribution settings</strong>” toggle.</li><li>Set your own custom attribution window values for that ad partner’s attribution types.</li></ol><h3 id="packaging" tabindex="-1">Packaging <a class="header-anchor" href="#packaging" aria-label="Permalink to &quot;Packaging&quot;">​</a></h3><p>Funnel is available as part of certain Branch plans. For more information, please see our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing page</a> or <a href="https://branchdocs.app.link/e/funnel-contact-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p><h2 id="use-funnel" tabindex="-1">Use Funnel <a class="header-anchor" href="#use-funnel" aria-label="Permalink to &quot;Use Funnel&quot;">​</a></h2><p>To access Funnel, go to <strong>Analysis &gt;</strong> <a href="https://branchdocs.app.link/funnel-new" target="_blank" rel="noreferrer"><strong>Funnel</strong></a> in Branch.</p><p>Funnel requires three parameters:</p><ul><li>The <strong>date range</strong> you want to see user journeys for.</li><li>The event that you consider the <strong>conversion event</strong> for your scenario.</li><li>The “compare by” <strong>dimension</strong> to break out the user journeys by, such as ad partner or campaign.</li></ul><p>In addition to these three parameters, you have the option to add <strong>filters</strong>. These are helpful if you only want to see certain campaigns, channels, features, etc.</p><p>Your chosen date range, conversion event, and “compare by” dimension will be displayed at the top of the screen, alongside any filters you’ve added.</p><h4 id="available-dimensions" tabindex="-1">Available dimensions <a class="header-anchor" href="#available-dimensions" aria-label="Permalink to &quot;Available dimensions&quot;">​</a></h4><p>The list of dimensions available for the required “compare by” field includes:</p><ul><li>Ad Set ID</li><li>Ad Set Name</li><li>Advertising Partner Name</li><li>Branch Channel</li><li>Campaign</li><li>Campaign ID</li><li>Feature</li><li>Keyword</li></ul><h4 id="available-filters" tabindex="-1">Available filters <a class="header-anchor" href="#available-filters" aria-label="Permalink to &quot;Available filters&quot;">​</a></h4><p>The list of filters you can add to your widget includes:</p><ul><li>Ad Set ID</li><li>Ad Set Name</li><li>Advertising Partner Name</li><li>Assist 1</li><li>Assist 2</li><li>Branch Channel</li><li>Campaign ID</li><li>Campaign Name</li><li>Channel</li><li>Conversion Event</li><li>Date</li><li>Feature</li><li>Geo Country</li><li>Keyword</li><li>Last Touch</li><li>OS</li></ul><h3 id="read-funnel-data" tabindex="-1">Read Funnel data <a class="header-anchor" href="#read-funnel-data" aria-label="Permalink to &quot;Read Funnel data&quot;">​</a></h3><p>Funnel has a strong visual component, as well as a structured table component. Use both views together to gain a more complete understanding of user engagement and drop-off points.</p><h4 id="read-visual-data" tabindex="-1">Read visual data <a class="header-anchor" href="#read-visual-data" aria-label="Permalink to &quot;Read visual data&quot;">​</a></h4><p>Funnel presents data visually in the form of a traditional Sankey diagram. Sankey diagrams have two main parts:</p><ul><li><p><strong>Nodes</strong>: These represent the different touchpoints a user goes through on their journey to a conversion event. Funnel will show up to three nodes, or touchpoints, before a conversion. This information is displayed in the form of text. Note that in a user journey with three touchpoints:</p><ul><li>Last Touch is the <em>most recent</em> touchpoint.</li><li>Assist 1 is the <em>second-to-last</em> touchpoint.</li><li>Assist 2 is the <em>initial</em> touchpoint.</li></ul></li></ul><p>If a user journey has fewer than three touchpoints, you will see that reflected with the <strong>No Touch</strong> label in the Assist 1 and/or Assist 2 columns.</p><ul><li><strong>Links</strong>:These are the colored lines that connect touchpoints together. By following these flows, you can track groups of user journeys between touchpoints, and see where they diverge or drop off.</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>By setting your date range and filters to be appropriately selective, you can make sure that you’re viewing a manageable number of flows at once.</p></div><p>To read the visual diagram:</p><ol><li><p>Find the identical horizontal lines at the top and bottom of the diagram, with the benchmarks <strong>Assist 2</strong>, <strong>Assist 1</strong>, <strong>Last Touch</strong>, and <strong>Conversion Event</strong>. User journeys move from left to right along these benchmarks.</p></li><li><p>Notice that user journeys are batched together based on having a shared touchpoint, and that the touchpoint is given a label. This label tells you what that touchpoint is attributed to.</p><ul><li>If a label says <strong>No Touch</strong>, follow the path(s) to the right until you see a label populated with data. This is where attributed touches start for those user journeys.</li></ul></li><li><p>Hover over one of the paths. A popover will appear that contains:</p><ul><li><strong>From</strong>: What <em>this</em>touchpoint is attributed to.</li><li><strong>To</strong>: What the <em>next</em> touchpoint is attributed to.</li><li><strong>Total Count</strong>: How many user journeys shared this particular section of the path.</li></ul></li><li><p>Observe that a single touchpoint is often the starting point for many different paths. Paths can start at the same touchpoint and then diverge. This can happen at the <strong>Assist 2</strong>, <strong>Assist 1</strong>, and/or <strong>Last Touch</strong> benchmarks.</p></li><li><p>All user journeys then converge at a single <strong>Conversion Event</strong>. The label for that touchpoint will reflect the name of the conversion event you set for your Funnel report.</p></li></ol><h4 id="read-structured-data" tabindex="-1">Read structured data <a class="header-anchor" href="#read-structured-data" aria-label="Permalink to &quot;Read structured data&quot;">​</a></h4><p>To view Funnel data as a table:</p><ol><li>At the <a href="./analysis-dashboards-overview-new.html#key-terms">widget</a> level, hover over the top-right corner of the Funnel visual diagram until the <strong>three-dot</strong>icon appears.</li><li>Select the <strong>three-dot</strong> icon.</li><li>Select <strong>Show underlying data</strong> from the menu that appears.</li></ol><p>Each row represents a unique scenario, and the <strong>Count</strong> column tells you how many users that scenario applies to. For example, if two users have all the same touchpoints but are on different operating systems or in different geolocations, they will be in separate rows in the table.</p><p>To change the columns included in the table:</p><ol><li>Select the <strong>Edit columns</strong> button.</li><li>Check the box next to each column you want to include in the table.</li><li>Select the <strong>Done</strong> button when you are finished.</li></ol><h3 id="use-ivy-for-insights" tabindex="-1">Use Ivy for insights <a class="header-anchor" href="#use-ivy-for-insights" aria-label="Permalink to &quot;Use Ivy for insights&quot;">​</a></h3><p>Funnel works best when you start with a specific marketing question in mind. Ivy, your powerful AI partner in Branch, can answer that question using your Funnel data and surface insights tailored to your situation.</p><p>Use the example questions in the table below to get started with Ivy in Funnel.</p><table tabindex="0"><thead><tr><th>Question for Ivy</th><th>Funnel configuration</th></tr></thead><tbody><tr><td>What channels perform best at different stages of the user journey?</td><td>Set the dimension to Channel.</td></tr><tr><td>What different path combinations result in the best conversion rates?</td><td>Set the dimension to Channel.</td></tr><tr><td>Which partners contribute most effectively to conversions?</td><td>Set the dimension to Ad Partner.</td></tr><tr><td>Which partners are more effective at first touch versus last touch?</td><td>Set the dimension to Ad Partner.</td></tr><tr><td>Are some of my campaigns better at initiating user journeys, while others are better at closing conversions?</td><td>Set the dimension to Campaign.</td></tr><tr><td>Do users in one country require more touchpoints than another country?</td><td>Set the dimension to Campaign or Channel, and add filters for the specific Geo country codes you want to compare.</td></tr><tr><td>What keywords appear in successful conversion paths, and at what touchpoints?</td><td>Set the dimension to Keyword and add the filter <code>Channel = Paid Search</code>.</td></tr><tr><td>Is CRM stealing credit from paid advertising?</td><td>Set the dimension to Channel or Feature - look for patterns where Paid Search or Paid Advertising appear early in the journey, followed by Email or CRM touchpoints at the end. If you see this frequently, your CRM might be getting last-click credit for conversions where paid campaigns served as crucial assisted touches earlier in the journey.</td></tr></tbody></table><h3 id="download-data" tabindex="-1">Download data <a class="header-anchor" href="#download-data" aria-label="Permalink to &quot;Download data&quot;">​</a></h3><p>To download the Funnel visual diagram as a PNG:</p><ol><li>At the <a href="./analysis-dashboards-overview-new.html#key-terms">widget</a> level, hover over the top-right corner of the Funnel visual diagram until the <strong>three-dot</strong> icon appears.</li><li>Select the <strong>three-dot</strong> icon.</li><li>Choose <strong>Download</strong> from the menu that appears.</li><li>Select <strong>PNG</strong> as the download type.</li><li>Select the <strong>Download</strong> button.</li></ol><p>To download the Funnel visual diagram as a PDF:</p><ol><li>At the <a href="./analysis-dashboards-overview-new.html#key-terms">dashboard</a> level, select the <strong>three-dot</strong> icon that lives to the right of the Ivy chat box.</li><li>Select <strong>Download PDF</strong> from the menu that appears.</li></ol><p>To download Funnel data as a structured table:</p><ol><li>At the <a href="./analysis-dashboards-overview-new.html#key-terms">widget</a> level, hover over the top-right corner of the Funnel visual diagram until the <strong>three-dot</strong> icon appears.</li><li>Select the <strong>three-dot</strong> icon.</li><li>Choose <strong>Download</strong> from the menu that appears.</li><li>Select <strong>XLSX</strong> or <strong>CSV</strong> as the download type.</li><li>Select the <strong>Download</strong> button.</li></ol><p>Alternatively, to download your Funnel data specifically as a CSV:</p><ol><li>At the <a href="./analysis-dashboards-overview-new.html#key-terms">widget</a> level, hover over the top-right corner of the Funnel visual diagram until the <strong>three-dot</strong> icon appears.</li><li>Select the <strong>three-dot</strong> icon.</li><li>Select <strong>Show underlying data</strong> from the menu that appears.</li><li>If you want to change the columns included in the table, select the <strong>Edit columns</strong> button and update your chosen columns.</li><li>When you’ve confirmed your columns look as expected, select the <strong>Download CSV</strong> button.</li></ol><h2 id="fields-reference" tabindex="-1">Fields reference <a class="header-anchor" href="#fields-reference" aria-label="Permalink to &quot;Fields reference&quot;">​</a></h2><p>The full list of fields available in Funnel are outlined in the table below.</p><table tabindex="0"><thead><tr><th>Field</th><th>Field Type</th><th>Description</th></tr></thead><tbody><tr><td>Ad Set Id</td><td>Dimension</td><td>The attributed ad set ID</td></tr><tr><td>Ad Set Name</td><td>Dimension</td><td>The attributed ad set name</td></tr><tr><td>Advertising Partner Name</td><td>Dimension</td><td>The attributed advertising partner name</td></tr><tr><td>App Id</td><td>Dimension</td><td>The Branch App Id</td></tr><tr><td>Assist 1</td><td>Dimension</td><td>The <strong>second</strong> touch attribution in the funnel path</td></tr><tr><td>Assist 2</td><td>Dimension</td><td>The <strong>first</strong> touch attribution in the funnel path</td></tr><tr><td>Branch Channel</td><td>Dimension</td><td>Identifies which Branch product or feature measured the attributed event</td></tr><tr><td>Campaign ID</td><td>Dimension</td><td>The attributed campaign ID</td></tr><tr><td>Campaign Name</td><td>Dimension</td><td>The attributed campaign name</td></tr><tr><td>Channel</td><td>Dimension</td><td>The attributed channel</td></tr><tr><td>Compare Dimension</td><td>Dimension</td><td>The dimension used for Funnel comparison</td></tr><tr><td>Conversion Event</td><td>Dimension</td><td>The conversion event type in the Funnel path</td></tr><tr><td>Count</td><td>Measure</td><td>The total count of conversions</td></tr><tr><td>Date</td><td>Dimension</td><td>Time-series date</td></tr><tr><td>Feature</td><td>Dimension</td><td>Indicates what Branch feature or link campaign was attributed</td></tr><tr><td>Geo Country</td><td>Dimension</td><td>The geographic country name in English</td></tr><tr><td>Keyword</td><td>Dimension</td><td>The attributed keyword</td></tr><tr><td>Last Touch</td><td>Dimension</td><td>The last touch attribution in the funnel path</td></tr><tr><td>OS</td><td>Dimension</td><td>Indicates the Operating System of the device</td></tr></tbody></table><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What is Branch Funnel?</summary><p>Branch Funnel simplifies multi-touch attribution reporting by visualizing the complete journey users take across campaigns before converting.</p></details><details><summary>How does Funnel differ from traditional last-touch attribution?</summary><p>Funnel tracks and displays the actual path users take, allowing you to see up to three interactions that led to each conversion, rather than just the last touchpoint.</p></details><details><summary>What are assisted touches?</summary><p>Assisted touches are touchpoints that appear in the conversion path but aren&#39;t the final interaction before conversion. These touchpoints play important supporting roles in the user journey, such as initial awareness or mid-funnel engagement, even though they don&#39;t receive last-touch credit.</p></details><details><summary>Can I set custom attribution windows for ad partners?</summary><p>Yes. You can <a href="./attribution-windows.html#disinheriting-attribution-window-settings-from-the-app-level">set custom attribution windows</a> at the ad partner level by turning on the <strong>Use ad partner attribution settings</strong> toggle at the ad partner level in Branch.</p></details><details><summary>What parameters are required to generate a Funnel report?</summary><p>You need to specify the date range, the conversion event, and a dimension to break out the user journeys by.</p></details><details><summary>What types of conversion events can I analyze with Funnel?</summary><p>You can analyze various conversion events, including Installs, <a href="./track-branch-events.html#standard-events">Branch Standard Events</a> like Add to Cart, or any other <a href="./track-branch-events.html#custom-events">Branch Custom Events</a> you’ve defined.</p></details><details><summary>Is Funnel available for all Branch plans?</summary><p>No, Funnel is only available as part of certain Branch plans. For more information, please <a href="https://branchdocs.app.link/e/funnel-contact-sales" target="_blank" rel="noreferrer">contact our Sales team</a> or reach out to your Account Manager.</p></details><details><summary>What visual representation does Funnel use?</summary><p>Funnel uses a traditional Sankey diagram to visually represent user journeys.</p></details><details><summary>What format can I download my Funnel data in?</summary><p>You can download the visual Sankey data as a PNG or PDF file, and the structured table data as a CSV or XLSX file.</p></details><details><summary>What should I do if I see the error message “One of your x-axis attributes contains too many values”?</summary><p>If you see this error message, you should apply more filters to your Funnel report. For example, you can filter down your results to just one country or operating system. This will narrow down the number of user journeys displayed into a more manageable number.</p></details>',74)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
